use mongodb::bson::{doc, DateTime, from_document};
use mongodb::{Client, Collection};
use serde::{Deserialize, Serialize};
use futures::TryStreamExt;

#[derive(Debug, Deserialize, Serialize)]
struct Movie {
    title: Option<String>,
    plot: Option<String>,
    genres: Option<Vec<String>>,
    released: Option<DateTime>,
}

#[tokio::main]
async fn main() -> mongodb::error::Result<()> {
    // Replace the placeholder with your connection string
    let uri = "<connection-string>";
    let client = Client::with_uri_str(uri).await?;

    let query = vec![
        doc! {
            "$search": {
                "index": "search_idx",
                "compound": {
                    "must": [
                        {
                            "text": {
                                "query": "baseball",
                                "path": "plot"
                            }
                        }
                    ],
                    "mustNot": [
                        {
                            "text": {
                                "query": ["Comedy", "Romance"],
                                "path": "genres"
                            }
                        }
                    ]
                },
                "sort": {
                    "released": -1
                }
            }
        },
        doc! {
            "$limit": 3
        },
        doc! {
            "$project": {
                "_id": 0,
                "title": 1,
                "plot": 1,
                "genres": 1,
                "released": 1
            }
        }
    ];

    let movies: Collection<Movie> = client
        .database("sample_mflix")
        .collection("movies");
    let mut cursor = movies.aggregate(query).await?;
    while let Some(doc) = cursor.try_next().await? {
        let movie: Movie = from_document(doc)?;
        println!("Title: {:?}", movie.title.unwrap_or_else(|| "N/A".to_string()));
        println!("Plot: {:?}", movie.plot.unwrap_or_else(|| "N/A".to_string()));
        println!("Genres: {:?}", movie.genres.unwrap_or_default());
        if let Some(released) = movie.released {
            println!("Released: {:?}", released);
        }
        println!();
    }

    Ok(())
}

#!/bin/bash
set -e

echo "Starting MongoDB initialization..."
sleep 2

# Create user using local connection (no port specification needed)
echo "Creating user..."
mongosh --eval "
const adminDb = db.getSiblingDB('admin');
try {
adminDb.createUser({
   user: 'mongotUser',
   pwd: 'mongotPassword',
   roles: [{ role: 'searchCoordinator', db: 'admin' }]
});
print('User mongotUser created successfully');
} catch (error) {
if (error.code === 11000) {
   print('User mongotUser already exists');
} else {
   print('Error creating user: ' + error);
}
}
"

# Check for existing data
echo "Checking for existing sample data..."
if mongosh --quiet --eval "db.getSiblingDB('sample_airbnb').getCollectionNames().includes('listingsAndReviews')" | grep -q "true"; then
echo "Sample data already exists. Skipping restore."
else
echo "Sample data not found. Running mongorestore..."
if [ -f "/sampledata.archive" ]; then
   mongorestore --archive=/sampledata.archive
   echo "Sample data restored successfully."
else
   echo "Warning: sampledata.archive not found"
fi
fi

echo "MongoDB initialization completed."

// Switch to the sample database
use sample_mflix

// Create a search index on the movies collection
db.movies.createSearchIndex(
   "default",
   { mappings:
      { dynamic: true }
   }
)

